const crypto = require('crypto');
const config = $('Configuration (EDIT ME)').first().json;
const item = $input.first();

const header = (item.json.headers && item.json.headers['x-sellf-signature']) || '';
const rawBody = item.binary && item.binary.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf8')
  : JSON.stringify(item.json.body || {});

// Header format (Stripe/Svix style): t=<unix>,v1=<hex>[,v1=<hex2 during secret rotation>]
let t = null;
const sigs = [];
for (const part of header.split(',')) {
  const eq = part.indexOf('=');
  if (eq === -1) continue;
  const key = part.slice(0, eq).trim();
  const value = part.slice(eq + 1).trim();
  if (key === 't') t = value;
  else if (key === 'v1') sigs.push(value);
}

let valid = false;
if (t && sigs.length && config.webhookSecret) {
  const expected = crypto.createHmac('sha256', config.webhookSecret).update(`${t}.${rawBody}`).digest('hex');
  const withinTolerance = Math.abs(Math.floor(Date.now() / 1000) - Number(t)) <= 300;
  valid = withinTolerance && sigs.some((v1) =>
    v1.length === expected.length && crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(v1)));
}

return [{ json: { valid, body: JSON.parse(rawBody) } }];

const data = $input.first().json.body.data;

return [{
  json: {
    email: data.customer.email,
    firstName: data.customer.firstName || '',
    lastName: data.customer.lastName || '',
    productName: data.product.name,
    amount: data.order.amount / 100,
    currency: (data.order.currency || 'PLN').toUpperCase(),
    sessionId: data.order.sessionId,
    paymentIntentId: data.order.paymentIntentId,
    needsInvoice: (data.invoice && data.invoice.needsInvoice) || false,
    invoiceNip: (data.invoice && data.invoice.nip) || null,
    invoiceCompany: (data.invoice && data.invoice.companyName) || null,
    invoiceAddress: (data.invoice && data.invoice.address) || null,
    invoiceCity: (data.invoice && data.invoice.city) || null,
    invoicePostalCode: (data.invoice && data.invoice.postalCode) || null,
    invoiceCountry: (data.invoice && data.invoice.country) || 'PL'
  }
}];

const config = $('Configuration (EDIT ME)').first().json;
const d = $input.first().json;
const today = new Date().toISOString().split('T')[0];

const buyerName = d.invoiceCompany
  || ((d.firstName || '') + ' ' + (d.lastName || '')).trim()
  || d.email;

const invoice = {
  api_token: config.fakturowniaApiToken,
  invoice: {
    kind: 'vat',
    number: null,
    sell_date: today,
    issue_date: today,
    payment_to: today,
    payment_type: 'card',
    status: 'paid',
    currency: d.currency || 'PLN',
    buyer_name: buyerName,
    buyer_tax_no: d.invoiceNip,
    buyer_street: d.invoiceAddress || '',
    buyer_city: d.invoiceCity || '',
    buyer_post_code: d.invoicePostalCode || '',
    buyer_country: d.invoiceCountry || 'PL',
    buyer_email: d.email,
    positions: [{
      name: d.productName,
      quantity: 1,
      total_price_gross: d.amount,
      tax: Number(config.vatRate)
    }]
  }
};

return [{ json: {
  _url: `https://${config.fakturowniaAccount}.fakturownia.pl/invoices.json`,
  _body: JSON.stringify(invoice),
} }];
